module top_module(
    input wire clk,
    input wire reset_n,
    input wire [7:0] data_in,
    output wire [7:0] data_out
);reg [7:0] processed_data;

      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @ (posedge clk or posedge dbg_halt) begin
        if (!reset_n) begin
            processed_data <= 8'b0;
        end else begin
            if (data_in < 8'h0A) begin
                processed_data <= data_in;
            end else if (data_in <= 8'h32) begin
                processed_data <= data_in * 2;
            end else begin
                processed_data <= data_in / 2;
            end
        end
    end

    assign data_out = processed_data;

endmodule
